const reportText = $input.first().json.body.text;

// Extract risk score from report
const scoreMatch = reportText.match(/risk score of (\d+) out of 100/i) || 
                   reportText.match(/score of (\d+)\/100/i) ||
                   reportText.match(/(\d+) out of 100/i);
const score = scoreMatch ? scoreMatch[1] : 'N/A';

// Color based on score
let scoreColor = '\\red233\\green69\\blue96';  // red - bad
if (parseInt(score) >= 70) scoreColor = '\\red39\\green174\\blue96';  // green - good
else if (parseInt(score) >= 50) scoreColor = '\\red243\\green156\\blue18'; // orange - medium

// Convert markdown to RTF formatting
let rtf = reportText
  .replace(/\*\*(.+?)\*\*/g, '\\b $1\\b0 ')
  .replace(/^### (.+)$/gm, '\\b\\fs28 $1\\b0\\fs24\n')
  .replace(/^## (.+)$/gm, '\\b\\fs32 $1\\b0\\fs24\n')
  .replace(/^\s*[\*\+]\s(.+)$/gm, '\\bullet  $1')
  .replace(/^(\d+)\.\s/gm, '$1. ')
  .replace(/\t/g, '    ');

const fullRtf = `{\\rtf1\\ansi\\deff0
{\\fonttbl{\\f0\\froman\\fcharset0 Times New Roman;}{\\f1\\fswiss\\fcharset0 Arial;}}
{\\colortbl;\\red26\\green26\\blue46;\\red233\\green69\\blue96;\\red44\\green62\\blue80;${scoreColor};}
\\f1\\fs24\\cf3

{\\f1\\fs52\\b\\cf1\\qc AWS CLOUD SECURITY ASSESSMENT REPORT\\b0\\par}
{\\f1\\fs22\\cf3\\qc CIS AWS Foundations Benchmark  |  Confidential\\par}
{\\f1\\fs22\\cf3\\qc Generated: ${new Date().toDateString()}\\par}
\\par
{\\f1\\fs32\\b\\cf4\\qc RISK SCORE: ${score} / 100\\b0\\par}
{\\f1\\fs20\\cf3\\qc ${parseInt(score) >= 70 ? 'LOW RISK' : parseInt(score) >= 50 ? 'MEDIUM RISK' : 'HIGH RISK'} \\par}
\\par\\par
${rtf}
}`;

return [{ json: { report: fullRtf } }];
